package com.schoolbus.controller;
import com.schoolbus.dto.request.*;import com.schoolbus.dto.response.*;import com.schoolbus.service.AdminCrudService;import jakarta.validation.Valid;import org.springframework.data.domain.*;import org.springframework.http.*;import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/api/v1/admin/routes") public class AdminRouteController{private final AdminCrudService s;public AdminRouteController(AdminCrudService s){this.s=s;}@GetMapping public ApiResponse<PageResponse<RouteResponse>> list(@RequestParam(required=false)String search,@RequestParam(defaultValue="0")int page,@RequestParam(defaultValue="20")int size){return ApiResponse.success(PageResponse.from(s.routes(search,PageRequest.of(page,size))));}@GetMapping("/{id}")public ApiResponse<RouteResponse> get(@PathVariable Long id){return ApiResponse.success(s.route(id));}@PostMapping public ResponseEntity<ApiResponse<RouteResponse>> create(@Valid @RequestBody RouteRequest r){return ResponseEntity.status(HttpStatus.CREATED).body(ApiResponse.success("Route created",s.createRoute(r)));}@PutMapping("/{id}")public ApiResponse<RouteResponse> update(@PathVariable Long id,@Valid @RequestBody RouteRequest r){return ApiResponse.success(s.updateRoute(id,r));}@PatchMapping("/{id}/deactivate")public ApiResponse<Void> deactivate(@PathVariable Long id){s.deactivateRoute(id);return ApiResponse.success("Route deactivated",null);}}
